
import { ValidateErrorEntity } from "ant-design-vue/es/form/interface";
import { Moment } from "moment";

import {
  defineComponent,
  onMounted,
  reactive,
  ref,
  toRaw,
  toRefs,
  UnwrapRef,
  watch,
} from "vue";
import UploadImg from "../../upload/UploadImg.vue";
import UploadFile from "../../upload/UploadFile.vue";
import CheckBatchnumber from "./CheckBatchnumber.vue";
import { add_sample } from "../../../server/http/api/user";
import Entrustmodel from "@/views/ProductionManagement/ATaskdelegation/notMenuPage/Createdelegate/madal/Entrustmodel.vue";
import { getTime } from "../../../utils/setData";
import { currentTime } from "../../../utils/currentTime";
import { useStore } from "vuex";
import { message } from "ant-design-vue";
import bus from "@/utils/bus";
export default defineComponent({
  components: {
    UploadImg,
    UploadFile,
    CheckBatchnumber,
    Entrustmodel,
  },
  props: ["product_arr", "selectDetail"],
  setup(props, { emit }) {
    const store = useStore();
    const batchNumberNode = ref();

    const formRef = ref();

    const formState: any = reactive({
      sampleName: "", //产品名称
      companyId: "", // 委托单位id
      specs: "", // 规格等级
      generation: "", // 代表批量
      sampleOrigin: "", // 样品产地
      sampleGroups: "", // 检测组数
      quantityPerGroup: "", // 每组数量
      manufacturer: "", // 生产厂家
      receivedDate: null, // 收样时间
      outward: [], // 样品外观
      inspector: "", // 验收员
      sampleRequirement: "", // 样品要求
      outwardDescribe: "",
      sampleQuantity: "",//样品数量
    });
    let data = reactive({
      num: 0,
    });

    onMounted(() => {
      // 初始化
      formState.quantityPerGroup = 1;
      formState.sampleGroups = 1;
      formState.receivedDate = currentTime();
      let userInfo: any = JSON.parse(store.state.userInfo);
      formState.inspector = userInfo.name;
    });

    watch(
      [() => formState.sampleGroups, () => formState.quantityPerGroup],
      (newval, o) => {
        //console.log(newval);
        data.num = newval[0] * newval[1];
        bus.emit("fileReset");
        //console.log(data.num);
      }
    );
    const rules = {
      sampleName: [
        {
          required: true,
          message: "必须填写产品名称",
        },
      ],
      companyId: [
        {
          required: true,
          message: "必须填写委托单位",
        },
      ],
      specs: [
        {
          required: true,
          message: "规格等级必填",
        },
      ],
    };
    const onSubmit = () => {
      formRef.value
        .validate()
        .then(() => {
          batchNumberNode.value.commitData(toRaw(formState));
        })
        .catch((error: ValidateErrorEntity<any>) => {
          //console.log("error", error);
        });
    };
    const resetForm = () => {
      formRef.value.resetFields();
    };

    const getselectDetail = (name: any) => {
      // emit("updateSelectDetail", name);
    };
    return {
      formRef,
      labelCol: { style: { width: "150px" } },
      wrapperCol: { span: 14 },
      other: "",
      formState,
      rules,
      ...toRefs(data),
      onSubmit,
      resetForm,
      batchNumberNode,
      getselectDetail,
    };
  },
});
