
import { cloneDeep } from "lodash-es";
import {
  defineComponent,
  onMounted,
  reactive,
  ref,
  toRaw,
  UnwrapRef,
  watch,
} from "vue";
import UploadImg from "../../upload/UploadImg.vue";
import bus from "@/utils/bus";
import { getTime } from "@/utils/setData";
import { add_sample } from "@/server/http/api/user";
import { message } from "ant-design-vue";
import router from "@/router";
import { useStore } from "vuex";

import { nanoid } from "nanoid";
const columns = [
  {
    title: "序号",
    dataIndex: "index",
    width: "15%",
    slots: { customRender: "index" },
  },
  {
    title: "批号/编号",
    dataIndex: "batchNumber",
    width: "25%",
    slots: { customRender: "batchNumber" },
  },
  {
    title: "样品照片",
    dataIndex: "picture",
    width: "40%",
    slots: { customRender: "picture" },
  },
  // {
  //   title: "操作",
  //   dataIndex: "operation",
  //   slots: { customRender: "operation" },
  // },
];
interface DataItem {
  key: string;
  name: string;
  age: number;
  address: string;
}

export default defineComponent({
  components: { UploadImg },
  props: ["num"],

  setup(props: any, ctx) {
    const store = useStore();
    // 表格数据
    const dataSource: any = ref([]);
    const files: any = ref([]);
    // var form = new FormData();
    // form.append("file", file);
    //   //console.log(form);
    // 添加文件
    const addFile = function (file: any) {
      files.value.push(file);
      //console.log(files.value);
    };
    // 删除文件
    const removeFile = function (fileName: string) {
      let index = files.value.findIndex((item: any) => {
        return item.name === fileName;
      });
      files.value.splice(index, 1);
      //console.log(files.value);
    };

    watch(
      () => props.num,
      (newval, o) => {
        dataSource.value = [];
        for (let i = 0; i < newval; i++) {
          dataSource.value.push({
            key: nanoid(),
            index: (i + 1).toString(),
            batchNumber: "",
            picture: "",
          });
        }
        files.value = [];
        dataSource.value.map((item: any) => {
          editableData[item.key] = item;
        });
      }
    );
    const editableData: UnwrapRef<Record<string, DataItem>> = reactive({});

    const edit = (key: string) => {
      editableData[key] = cloneDeep(
        dataSource.value.filter((item: any) => key === item.key)[0]
      );
      console.log(editableData[key]);
    };
    const saveChange = (v: any, key: any) => {
      Object.assign(
        dataSource.value.filter((item: any) => key === item.key)[0],
        editableData[key]
      );
      // delete editableData[key];
    };
    const save = (key: string) => {
      console.log(key);

      Object.assign(
        dataSource.value.filter((item: any) => key === item.key)[0],
        editableData[key]
      );
      delete editableData[key];
    };
    const cancel = (key: string) => {
      delete editableData[key];
    };

    const commitData = (formData: any) => {
      let willdataSource: any[] = [];
      let willformData: any = {};
      Object.assign(willformData, toRaw(formData));
      dataSource.value.forEach((item: any) => {
        willdataSource.push({
          index: item.index,
          batchNumber: item.batchNumber,
          picture: "",
        });
      });
      Object.assign(willformData, {
        outward:
          willformData.outward.join("、") + "、" + willformData.outwardDescribe,
        details: willdataSource,
      });
      if (files.value.length !== props.num) {
        message.info("样品照片未上传！");
        return;
      }
      // // file对象
      let Files = new FormData();
      files.value.forEach((file: any) => {
        Files.append("file", file);
      });

      if (willformData.receivedDate) {
        Object.assign(willformData, {
          receivedDate: getTime(willformData.receivedDate._d),
        });
      }
      // console.log(willformData);
      // 添加json
      Files.append("json", JSON.stringify(willformData));
      add_sample(Files).then((res: any) => {
        //console.log(res);
        if (res.data.code === 200) {
          message.success("保存成功");
          router.replace({ name: "SampleSearch" });
        }
      });
    };

    return {
      dataSource,
      columns,
      editingKey: "",
      editableData,
      edit,
      save,
      cancel,
      addFile,
      removeFile,
      files,
      commitData,
      saveChange,
    };
  },
});
