
import { defineComponent, reactive, toRef, toRefs } from "vue";
import SampleFrom from "../../../components/ATestdetection/Sample/SampleFrom.vue";
import {
  get_sample_product_name,
  get_select_value,
} from "../../../server/http/api/user";
export default defineComponent({
  name: "Sample",
  components: {
    SampleFrom,
  },
  setup() {
    let data = reactive({
      product_arr: [],
      selectDetail: [],
    });
    const updateSelectDetail = () => {
      get_select_value().then((res: any) => {
        if (res.data.code === 200) {
          data.selectDetail = res.data.data;
        }
      });
    };
    // 查询产品检测项
    get_sample_product_name().then((res: any) => {
      if (res.data.code === 200) {
        data.product_arr = res.data.data;
      }
    });
    // 查询委托单位 、样品外观
    get_select_value().then((res: any) => {
      if (res.data.code === 200) {
        data.selectDetail = res.data.data;
      }
    });

    return {
      ...toRefs(data),
      updateSelectDetail,
    };
  },
});
