
import { UploadOutlined } from "@ant-design/icons-vue";
import { message } from "ant-design-vue";
import { defineComponent, onMounted, onUnmounted, ref } from "vue";
import { nanoid } from "nanoid";
import bus from "@/utils/bus";
interface FileItem {
  uid: string;
  name?: string;
  status?: string;
  response?: string;
  url?: string;
  preview?: string;
  originFileObj?: any;
  file: string | Blob;
}

export default defineComponent({
  props: ["record", "text"],
  components: {
    UploadOutlined,
  },
  setup(props, ctx) {
    const fileList = ref<any[]>([]);

    const handleRemove = (file: FileItem) => {
      const index = fileList.value.indexOf(file);
      const newFileList = fileList.value.slice();
      newFileList.splice(index, 1);
      fileList.value = newFileList;
      //console.log(fileList.value);
      ctx.emit("removeFile", file.name);
    };

    const beforeUpload = (file: any) => {
      let suffix_arr = file.name.split(".");
      var renameFile: any = new File(
        [file],
        props.record.index + "." + suffix_arr[suffix_arr.length - 1],
        {
          type: file.type,
        }
      );
      renameFile.uid = nanoid();
      fileList.value = [...fileList.value, renameFile];
      ctx.emit("addFile", renameFile);
      return false;
    };

    onMounted(() => {
      bus.on("fileReset", () => {
        fileList.value = [];
      });
    });

    onUnmounted(() => {
      bus.off("fileReset");
    });

    return {
      fileList,
      handleRemove,
      beforeUpload,
    };
  },
});
